// ============================================================
// NŒUD 2 — Validate Auth
// Vérifie le secret webhook (via variable env n8n : LISTING_WEBHOOK_SECRET)
// et extrait le body pour les nœuds suivants.
// Doc : aligner LISTING_IMPORT_N8N_WEBHOOK_SECRET dans .env Next avec
// LISTING_WEBHOOK_SECRET dans les variables d'environnement n8n.
// ============================================================

const incoming = $input.first();
const body = incoming.json?.body || incoming.json || {};
const headers = incoming.headers || {};

// $env.LISTING_WEBHOOK_SECRET : variable n8n instance (Settings → Variables)
// Si absente ou vide, aucune vérification de secret.
const secret = ($env.LISTING_WEBHOOK_SECRET || '').trim();
const incomingSecret = (headers['x-webhook-secret'] || headers['X-Webhook-Secret'] || '').trim();
const secretOk = !secret || incomingSecret === secret;
const sourceOk = body.source === 'listing_import_enrich';

return [{ json: { secretOk, sourceOk, body } }];

// ============================================================
// NŒUD 7 — Compute Keys
// Calcule missingKeys (champs vides) et suspectKeys (champs remplis
// mais potentiellement erronés) à passer au LLM.
// ============================================================

const incoming = $input.first().json;
const body = incoming.body || incoming || {};
const parsed = body.parsed || {};
const pageText = body.pageText || '';
const pageUrl = body.pageUrl || '';
const extractionInstructions = body.extractionInstructions || '';

const allKeys = ['name','description','location','capacity','price_per_night','bathrooms_count','surface_m2','check_in_time','check_out_time','latitude','longitude','house_rules','amenities'];

function isEmpty(v) {
  if (v == null) return true;
  if (typeof v === 'string') return v.trim() === '';
  if (typeof v === 'number') return !isFinite(v);
  if (Array.isArray(v)) return v.length === 0;
  return false;
}

const missingKeys = allKeys.filter(k => isEmpty(parsed[k]));
const suspectKeys = [];
const suspectReasons = {};

if (!isEmpty(parsed.price_per_night)) {
  const p = Number(parsed.price_per_night);
  if (isNaN(p) || p < 10 || p > 50000) {
    suspectKeys.push('price_per_night');
    suspectReasons.price_per_night = 'valeur ' + parsed.price_per_night + ' hors bornes attendues (10-50000€)';
  }
}
if (!isEmpty(parsed.capacity)) {
  const c = Number(parsed.capacity);
  if (isNaN(c) || c < 1 || c > 30) {
    suspectKeys.push('capacity');
    suspectReasons.capacity = 'valeur ' + parsed.capacity + ' suspecte (attendu 1-30)';
  }
}
if (!isEmpty(parsed.description) && String(parsed.description).trim().length < 40) {
  suspectKeys.push('description');
  suspectReasons.description = 'trop courte (' + String(parsed.description).trim().length + ' chars, min 40)';
}
if (!isEmpty(parsed.name) && String(parsed.name).trim().length < 3) {
  suspectKeys.push('name');
  suspectReasons.name = 'trop court (' + String(parsed.name).trim().length + ' chars)';
}
if (!isEmpty(parsed.surface_m2)) {
  const s = Number(parsed.surface_m2);
  if (isNaN(s) || s < 10 || s > 10000) {
    suspectKeys.push('surface_m2');
    suspectReasons.surface_m2 = 'hors bornes ' + parsed.surface_m2 + ' (10-10000 m2)';
  }
}

const missingKeysText = missingKeys.length > 0 ? missingKeys.join(', ') : '(aucun)';
const suspectKeysText = suspectKeys.length > 0
  ? suspectKeys.map(k => '- ' + k + ' : ' + suspectReasons[k]).join('\n')
  : '(aucun)';

return [{
  json: {
    pageUrl,
    pageText,
    extractionInstructions,
    parsedJson: JSON.stringify(parsed, null, 2),
    missingKeys: missingKeysText,
    suspectKeys: suspectKeysText
  }
}];

