// ============================================================
// NŒUD 9 — Parse & Clean
// Parse la réponse JSON du LLM, supprime image_url/image_urls,
// valide qu'au moins un champ utile est présent.
// ============================================================

const input = $input.first().json;
const rawOutput = input.output || input.text || input.response || input.content || input.message || '';

function extractJSON(text) {
  if (!text || typeof text !== 'string') return null;
  const t = text.trim();
  // Tentative 1 : parse direct
  try { return JSON.parse(t); } catch(e) {}
  // Tentative 2 : premier bloc {...}
  const start = t.indexOf('{');
  const end = t.lastIndexOf('}');
  if (start >= 0 && end > start) {
    try { return JSON.parse(t.slice(start, end + 1)); } catch(e) {}
  }
  // Tentative 3 : bloc ```json...```
  const match = t.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (match) {
    try { return JSON.parse(match[1].trim()); } catch(e) {}
  }
  return null;
}

const parsed = extractJSON(rawOutput);

if (!parsed || typeof parsed !== 'object' || Array.isArray(parsed)) {
  return [{
    json: {
      parseOk: false,
      error: 'LLM response not parseable as JSON. Raw: ' + String(rawOutput).slice(0, 300)
    }
  }];
}

// Supprimer les clés interdites
delete parsed.image_url;
delete parsed.image_urls;

const usefulKeys = ['name','description','location','capacity','price_per_night','bathrooms_count','surface_m2','check_in_time','check_out_time','latitude','longitude','house_rules','amenities'];
const hasUseful = usefulKeys.some(k => k in parsed && parsed[k] != null);

return [{
  json: {
    parseOk: hasUseful,
    listing: parsed,
    error: hasUseful ? null : 'No useful listing fields in LLM response'
  }
}];
